class Solution:
    def distinctSequences(self, n: int) -> int:
        MOD = 10**9 + 7
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            for j in range(1, 7):
                if i > 1 and dp[i - 1] % (j * (j - 1)) != 0:
                    dp[i] = (dp[i] + dp[i - 1]) % MOD
        return dp[n]

